/*
  Course: INT-499 Capstone in Information Technology
  Instructor: John Russel
  Joshua Coman
*/

export default function StreamList({ searchTerm }) {
  const [items, setItems] = useState([]);
  const [input, setInput] = useState("");
  const [editingIndex, setEditingIndex] = useState(null);

  // Add or update item
  const handleAdd = () => {
    if (input.trim() === "") return;
    if (editingIndex !== null) {
      const updatedItems = [...items];
      updatedItems[editingIndex].text = input;
      setItems(updatedItems);
      setEditingIndex(null);
    } else {
      setItems([...items, { text: input, completed: false }]);
    }
    setInput("");
  };

  // Filtered list based on search
  const filteredItems = items.filter(item =>
    item.text.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="streamlist-container">
      <h2>StreamList</h2>
      <div className="input-group">
        <input
          type="text"
          value={input}
          placeholder="Enter item..."
          onChange={(e) => setInput(e.target.value)}
        />
        <button onClick={handleAdd}>{editingIndex !== null ? "Update" : "Add"}</button>
      </div>

      <ul className="items-list">
        {filteredItems.map((item, index) => (
          <li key={index} className={item.completed ? "completed" : ""}>
            <span>{item.text}</span>
            <div className="item-buttons">
              <button onClick={() => {
                const updatedItems = [...items];
                updatedItems[index].completed = !updatedItems[index].completed;
                setItems(updatedItems);
              }}>
                <FaCheck />
              </button>
              <button onClick={() => {
                setInput(item.text);
                setEditingIndex(index);
              }}>
                <FaEdit />
              </button>
              <button onClick={() => {
                const updatedItems = items.filter((_, i) => i !== index);
                setItems(updatedItems);
              }}>
                <FaTrash />
              </button>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}
